package com.aadil.jobtracker.exceptions;import lombok.Getter;import java.time.LocalDateTime;@Getterpublic class ErrorResponse {    private String message;    private int status;    private LocalDateTime timeStamp;    public ErrorResponse(String message,int status,LocalDateTime timeStamp){        this.message=message;        this.status=status;        this.timeStamp=timeStamp;    }}